241	// checkBinaryInstallLocation verifies the running binary is at the canonical install
242	// location ($HOME/.local/bin/ddx) and scans PATH for other ddx copies whose
243	// SHA-256 differs from the running binary.
244	func checkBinaryInstallLocation(executable string) []DiagnosticIssue {
245		var issues []DiagnosticIssue
246	
247		homeDir, err := os.UserHomeDir()
248		if err != nil {
249			return issues
250		}
251	
252		canonicalPath := filepath.Join(homeDir, ".local", "bin", "ddx")
253	
254		// (2) Check whether running binary matches the canonical install location.
255		resolvedExec, _ := filepath.EvalSymlinks(executable)
256		if resolvedExec == "" {
257			resolvedExec = executable
258		}
259		resolvedCanonical, _ := filepath.EvalSymlinks(canonicalPath)
260		execMatchesCanonical := resolvedExec == canonicalPath ||
261			(resolvedCanonical != "" && resolvedExec == resolvedCanonical)
262		if !execMatchesCanonical {
263			issues = append(issues, DiagnosticIssue{
264				Type:        "binary_not_canonical",
265				Description: fmt.Sprintf("Running binary (%s) is not at canonical install location (%s)", executable, canonicalPath),
266				Remediation: []string{
267					"Re-run install.sh to reinstall to the canonical location",
268					fmt.Sprintf("Or ensure %s is earlier in your PATH", filepath.Dir(canonicalPath)),
269				},
270			})
271		}
272	
273		// (3) Walk PATH and flag any ddx copy whose SHA-256 differs from the running binary.
274		runningSHA, err := computeFileSHA256(executable)
275		if err != nil {
276			return issues
277		}
278	
279		seen := make(map[string]bool)
280		for _, dir := range filepath.SplitList(os.Getenv("PATH")) {
281			candidate := filepath.Join(dir, "ddx")
282			if seen[candidate] {
283				continue
284			}
285			seen[candidate] = true
286	
287			info, err := os.Stat(candidate)
288			if err != nil || !info.Mode().IsRegular() || info.Mode()&0111 == 0 {
289				continue
290			}
291	
292			candidateSHA, err := computeFileSHA256(candidate)
293			if err != nil {
294				continue
295			}
296	
297			if candidateSHA == runningSHA {
298				continue // same binary, not stale
299			}
300	
301			issues = append(issues, DiagnosticIssue{
302				Type:        "binary_sha_mismatch",
303				Description: fmt.Sprintf("Stale ddx copy on PATH: %s (SHA-256 differs from running binary)", candidate),
304				Remediation: []string{
305					fmt.Sprintf("rm %s && cp %s %s", candidate, executable, candidate),
306					"Or re-run install.sh to update all copies",
307				},
308			})
309		}
310	
311		return issues
312	}
