314	// computeFileSHA256 returns the hex-encoded SHA-256 digest of the named file.
315	func computeFileSHA256(path string) (string, error) {
316		f, err := os.Open(path)
317		if err != nil {
318			return "", err
319		}
320		defer f.Close()
321	
322		h := sha256.New()
323		if _, err := io.Copy(h, f); err != nil {
324			return "", err
325		}
326		return hex.EncodeToString(h.Sum(nil)), nil
327	}
