590	func looksLikePluginInstall(entry registry.InstalledEntry) bool {
591		candidates := make([]string, 0, 2+len(entry.Files))
592		if root := installedEntryRootCandidate(entry); root != "" {
593			candidates = append(candidates, root)
594		}
595		candidates = append(candidates, entry.Files...)
596	
597		for _, candidate := range candidates {
598			path := registry.ExpandHome(strings.TrimSpace(candidate))
599			if path == "" {
600				continue
601			}
602	
603			info, err := os.Lstat(path)
604			if err != nil {
605				continue
606			}
607	
608			if info.IsDir() || info.Mode()&os.ModeSymlink != 0 {
609				return true
610			}
611		}
612	
613		return false
614	}
